parameters.jsCode:
const results = $input.first().json;
const found = Array.isArray(results) && results.length > 0;

return [{
  json: {
    customerFound: found ? "yes" : "no",
    record: found ? results[0] : null,
    phone: $("Normalize Phone").first().json.phone,
    name: $("Normalize Phone").first().json.name,
    job_description: $("Normalize Phone").first().json.job_description
  }
}];
